var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"곤란한 일이라니, 그게 뭐지?","JPN":"困ったことって、何だ？","ENG":"A problem? What is it?","TWN":"麻煩事？什麼麻煩事？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"실은 등대에 문제가 생겼어.","JPN":"実は、灯台に問題が起きてな。","ENG":"It has to do with the Lighthouse.","TWN":"其實是燈塔出了問題。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐? 그게 무슨 말이지?","JPN":"え？　どういうことだ？","ENG":"What? What do you mean?","TWN":"什麼？什麼意思？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"분명 공격해 오는 침식체들은 모두 막아냈는데......","JPN":"攻撃してきた侵食体は残さず退治したはずだが……","ENG":"I fended off all the C.O.s I saw.","TWN":"我們明明已經擋下了所有攻過來的侵蝕體……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"설마 내가 보지 못한 방향에서 기습이라도 당한 건가?","JPN":"まさか死角から奇襲でもうけたのか？","ENG":"Did some of them come from where I couldn't see them?","TWN":"難道是在我沒看到的方向遭到了奇襲？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그건 아니야. 당신은 완벽하게 침식체를 막아냈어.","JPN":"そうじゃない。君の侵食体対応は完璧だった。","ENG":"No. You stopped all the C.O.s. There's no doubt about it.","TWN":"不是的，你完美地擋下了侵蝕體。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"하지만 차원 폭풍이 점점 더 강해지고 있는 게 문제야.","JPN":"だが、次元の暴風がさらに勢力を拡大しているのが問題だ。","ENG":"I'm talking about the dimensional storm. It's growing stronger.","TWN":"但問題是次元風暴越來越猛烈了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"왜 이런 현상이 발생하는지는 모르겠지만, 등대의 부품들이 심하게 부하를 받고 있어.","JPN":"なぜこんな現象が起きているかはわからないが、\\n灯台の部品に強い負荷がかかっている。","ENG":"I don't know why it is, but it's putting a lot of strain on the components of the Lighthouse.","TWN":"雖然不知道為什麼會發生這種現象，但燈塔部件的負荷越來越嚴重了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"이대로 가다간 곧 등대가 고장 나고 말 거야.","JPN":"このままだと灯台が壊れてしまうだろう。","ENG":"Sooner or later, the Lighthouse will break.","TWN":"再這樣下去，燈塔很快會故障的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐라고? 막을 수 있는 방법은 없나?","JPN":"何だって？　阻止する方法はないのか？","ENG":"What? Can't we stop it?","TWN":"你說什麼？沒有什麼解決辦法嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"등대가 고장 나면 차원 폭풍 안으로 진입한 소장님이 빠져 나올 수가 없잖아!","JPN":"灯台が壊れたら少将が出られなくなるじゃないか！","ENG":"Without the Lighthouse, the Major General can't find her way out of the dimensional storm.","TWN":"燈塔要是故障，進入次元風暴內部的少將大人不就無法脫離了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그러니까 하는 말이지.","JPN":"だから相談してるんだ。","ENG":"That's why I'm talking to you right now.","TWN":"所以我才來和你說這件事。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"우리도 명색이 정보부 요원들이라고. 여기서 전투식량만 축내고 있던 게 아니야.","JPN":"こう見えて我々も情報局員だからな。ここでただ飯食ってたわけじゃないぞ。","ENG":"We're intelligence agents. We haven't just been sitting here, wasting our combat rations.","TWN":"我們好歹是情報部要員啊，可不只是在這裡浪費戰鬥食糧的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"분석 결과 차원 폭풍을 증폭시키는 침식 쐐기들이 근처에 포진하고 있어.","JPN":"分析した結果、次元の暴風を拡大させる侵食楔が近くに布陣している。","ENG":"We looked around. There are Corrupted Wedges around here, and they're intensifying the dimensional storm.","TWN":"分析的結果顯示，附近陣列著能使次元風暴增幅的侵蝕釘。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"조금......","JPN":"少し……","ENG":"It may be a little bit—","TWN":"雖然有些……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"아니, 매우 위험하긴 하지만 이 침식 쐐기들을 처치할 수만 있다면 차원 폭풍의 강도를 일시적으로 약화시킬 수 있을 거야.","JPN":"いや、非常に危険ではあるがこの侵食楔を排除すれば、次元の暴風の強度を一時的に弱めることができるだろう。","ENG":"Actually, it's going to be very dangerous, but if we take care of these Corrupted Wedges, we can weaken the dimensional storm, though only temporarily.","TWN":"不，雖然非常危險，但只要能解決掉這些侵蝕釘，就能暫時減弱次元風暴的強度。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그럼 등대에 가해지는 부하도 조금은 줄어들겠지.","JPN":"そうすれば灯台にかかっている負荷も少しは弱まるはずだ。","ENG":"And that should lessen the burden on the Lighthouse.","TWN":"這樣燈塔的負荷也能減輕了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐야? 생각보다 간단하잖아?","JPN":"何だ、思ったより簡単じゃないか。","ENG":"What? That's easier than I thought.","TWN":"什麼？這比我想的還要簡單嘛？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그러니까 전부 박살 내 버리면 된다는 거지?","JPN":"つまり、全滅させりゃいいってことだよな？","ENG":"So, we just need to get rid of them all, right?","TWN":"所以把那些侵蝕釘全都摧毀就行了？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"......요약하면 그렇지.","JPN":"……端的に言えばそうだ。","ENG":"Erm, in short, yeah.","TWN":"……簡單來說就是這樣。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"하지만 외곽이긴 해도 차원 폭풍 내부로 진입해야 하는 일이야.","JPN":"けど、中心部ではなくとも次元の暴風の中に入らなければならないんだ。","ENG":"But we still have to enter the dimensional storm. Not too deeply, though.","TWN":"但雖說是在次元風暴週邊，你還是得進到次元風暴內部。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"정말 위험하다고. 그래도 할 건가?","JPN":"相当な危険を伴うことだ。それでもやるのか？","ENG":"It really is dangerous. Are you still up for it?","TWN":"這真的很危險。就算如此你也要去嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"물론이지.","JPN":"もちろんだ。","ENG":"Of course.","TWN":"那當然。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"위험한 작전이야말로 소장님의......","JPN":"危険な作戦こそが少将の……","ENG":"Dangerous operations are the Major General's—","TWN":"畢竟進行危險的作戰正是少將大人的……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아니, 우리 델타 세븐의 특기니까.","JPN":"いや、我がデルタセブンの専門だからな。","ENG":"I mean, they're us Delta Seven's forte.","TWN":"不，正是我們第七三角洲的特長。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"좋아. 이야기가 빨라서 좋군.","JPN":"よし。話が早くて助かる。","ENG":"Good, I'm glad we settled it quickly.","TWN":"很好，能這麼快就達成共識，真是太好了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그럼 길잡이는 이 친구가 맡을 걸세.","JPN":"では、道案内は彼が担当するから。","ENG":"He'll be your guide.","TWN":"那就由這位朋友負責帶路了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"뭐? 내, 내가 왜?!","JPN":"えっ？　な、なんで、俺！？","ENG":"What? M-me? Why me?","TWN":"什麼？為、為什麼是我？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"차원 폭풍 내부는 GPS도 안 먹힌다고. 길안내를 할 사람이 필요해.","JPN":"次元の暴風の中はGPSすら使えないんだ。案内役が必要なんだよ。","ENG":"Even GPS doesn't work inside dimensional storms. He needs help navigating his way.","TWN":"因為次元風暴內部連GPS都無法使用。需要有一個帶路的人啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"자네는 카운터잖아? 우리 같은 일반인들보다는 침식파 내성도 강하니까 길잡이로 적격이지.","JPN":"君はカウンターだろ？\\n我々のような一般人よりかは侵食波への耐性も強いし、案内役としてピッタリさ。","ENG":"You're a Counter. You're more resistant to Corruption Rays than ordinary people like us. You have to be the guide.","TWN":"你不是制裁者嗎？你對侵蝕波的耐性也比我們一般人強，所以很適合帶路啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"이터니움 실드는 어디다 팔아먹었냐?! 네가 가면 되잖아!","JPN":"エタニウムシールドはどこに売り払ったんだ！？　あんたが行けばいいだろ？","ENG":"But you have an Eternium shield! You go yourself!","TWN":"你們的永恆之金護盾是都毀了還是怎樣？！你自己去不就好了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그래? 그럼 할 일을 바꿀까? 여기라고 별로 편하진 않을 텐데.","JPN":"なるほど、じゃあ任務を交換するか？　ここだって楽ではないと思うぞ。","ENG":"Oh, yeah? You want to switch places with me? Things won't be any easier here.","TWN":"是嗎？那你要不要換個差事做做？我這裡也沒有多輕鬆喔。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>차원 폭풍으로부터 침식체 제 3파 다수 접근!</color>","JPN":"<color=#ffd34c>次元の暴風から侵食体の第3波が複数接近中！</color>","ENG":"<color=#ffd34c>Here comes the third wave! Multiple C.O.s oncoming from the dimensional storm!</color>","TWN":"<color=#ffd34c>許多3類侵蝕體正從次元風暴接近！</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>전원 요격 태세로!</color>","JPN":"<color=#ffd34c>全員迎撃に備えよ！</color>","ENG":"<color=#ffd34c>Everyone, get ready to fight!</color>","TWN":"<color=#ffd34c>全員準備迎擊！</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"들었지? 나라면 이런 곳에선 최강의 전투원 옆에 붙어 있는 편을 택할 거야.","JPN":"聞こえたか？\\n自分ならこんな場所では最強戦闘員にピッタリくっつくほうを選ぶよ。","ENG":"Hear that? If I were you, I'd choose to stay with the strongest combatant of us all.","TWN":"聽到了吧？是我的話，我就會選擇緊跟在這裡最強的戰鬥要員身邊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L41_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"빨리 결정하라고.","JPN":"早く決めろよ。","ENG":"But it's your call.","TWN":"快點下決定吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"......가, 간다고! 가면 되잖아!","JPN":"……い、行くよ！　行けばいいんだろ！","ENG":"O-okay, okay! I'll go!","TWN":"……我、我去啦！我去就行吧！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"잘 생각했어.","JPN":"そう来なくちゃな。","ENG":"Good thinking.","TWN":"不錯的想法。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"지난번에 민간 위장 기업 쪽으로 전출을 요청한 것 같던데, 이번 일만 잘 마치면 나도 추천서를 써 주지.","JPN":"この前民間企業を装った組織への出向を申請したようだが\\n今回の件さえうまくいけば、私からも推薦書を書いてやろう。","ENG":"I know you've requested a transfer to a civilian front organization. If this goes well, I'll write you a letter of recommendation.","TWN":"你之前好像有提出申請，說要調到民間偽裝企業。如果你這次能成功完成任務，我會給你寫封推薦信的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그럼 어서 가! 우리가 버틸 수 있는 시간은 짧다고!","JPN":"さあ、早く行け！　我々が持ちこたえられる時間は短いんだ！","ENG":"Now, go. We can only last for so long.","TWN":"那就快走吧！我們能堅持的時間也很短！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};